package com.socialblog.interaction.api;import com.socialblog.interaction.application.InteractionService;import com.socialblog.interaction.application.InteractionService.State;import com.socialblog.interaction.domain.TargetType;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.util.UUID;@RestController @RequestMapping("/api/v1/interactions")public class InteractionController{private final InteractionService service;public InteractionController(InteractionService s){service=s;}@GetMapping("/{type}/{target}")State get(@PathVariable TargetType type,@PathVariable UUID target,@AuthenticationPrincipal Jwt j){return service.get(j==null?null:UUID.fromString(j.getSubject()),type,target);}@PutMapping("/{type}/{target}/like")State like(@PathVariable TargetType type,@PathVariable UUID target,@AuthenticationPrincipal Jwt j){return service.like(UUID.fromString(j.getSubject()),type,target);}@DeleteMapping("/{type}/{target}/like")State unlike(@PathVariable TargetType type,@PathVariable UUID target,@AuthenticationPrincipal Jwt j){return service.unlike(UUID.fromString(j.getSubject()),type,target);}}
